import sys
from typing import List

class Solution:
    def stockSpan(self, prices: List[int]) -> List[int]:
        stack = []
        result = []
        for i, price in enumerate(prices):
            while stack and prices[stack[-1]] <= price:
                stack.pop()
            if not stack:
                result.append(i + 1)
            else:
                result.append(i - stack[-1])
            stack.append(i)
        return result

if __name__ == '__main__':
