#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> stockSpan(vector<int>& prices) {
        stack<int> st;
        vector<int> result;
        for (int i = 0; i < prices.size(); i++) {
            while (!st.empty() && prices[st.top()] <= prices[i]) {
                st.pop();
            }
            if (st.empty()) {
                result.push_back(i + 1);
            } else {
                result.push_back(i - st.top());
            }
            st.push(i);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int discard;
    cin >> discard;
    int n;
    cin >> n;
    vector<int> prices(n);
    for (int i = 0; i < n; i++) cin >> prices[i];
    Solution sol;
    vector<int> ans = sol.stockSpan(prices);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : "\n");
    }
    cout << "\n";
    return 0;
}
